 159→const parseLimitWithinRange = (value, min, max, fallback = null) => {
 160→    const parsed = Number.parseInt(value, 10);
 161→    if (Number.isNaN(parsed)) {
 162→        return fallback;
 163→    }
 164→    if (parsed < min || parsed > max) {
 165→        return null;
 166→    }
 167→    return parsed;
