 274→router.get('/getFollowsData', async(req, res) => {
 275→    const {userId, loggedInUserId} = req.query;
 276→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 277→    // console.log(req.query)
 278→    try {
 279→        const followersCountPromise = supabase
 280→        .from('follows')
 281→        .select('*', {count: 'exact', head: true})
 282→        .eq('following_id', userId);
 283→
 284→        const followingCountPromise = supabase
 285→        .from('follows')
 286→        .select('*', {count: 'exact', head: true})
 287→        .eq('follower_id', userId)
 288→
 289→        const isFollowingPromise = supabase
 290→        .from('follows')
 291→        .select('*', {count: 'exact', head: true})
 292→        .eq('follower_id', loggedInUserId)
 293→        .eq('following_id', userId)
 294→
 295→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 296→            followersCountPromise, followingCountPromise, isFollowingPromise,
 297→        ])
 298→
 299→
 300→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 301→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 302→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 303→
 304→        if(errorFollowers || errorFollowings || errorIsfollowing){
 305→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 306→            return res.status(500).json({error: 'failed to fetch data'})
 307→        }
 308→
 309→        return res.status(200).json({
 310→            followersCount: followersCount,
 311→            followingsCount: followingsCount,
 312→            isFollowing: isFollowingCount > 0
 313→        })
 314→
 315→    } catch (error) {
 316→        console.error('Error in Promise.all:', error);
 317→        res.status(500).json({ error: 'An unexpected error occurred' });
 318→    }
 319→
 320→})
