  80→const attachRepostSources = async (journals) => {
  81→    const items = Array.isArray(journals) ? journals : [journals];
  82→    const sourceIds = [...new Set(
  83→        items
  84→            .filter(j => j.is_repost === true && j.repost_source_journal_id != null)
  85→            .map(j => j.repost_source_journal_id)
  86→    )];
  87→
  88→    if (sourceIds.length === 0) {
  89→        items.forEach(j => { j.repost_source = null; });
  90→        return journals;
  91→    }
  92→
  93→    const { data: sources, error } = await supabase
  94→        .from('journals')
  95→        .select('id, title, content, post_type, created_at, users(id, name, image_url, badge)')
  96→        .in('id', sourceIds);
  97→
  98→    if (error) {
  99→        console.error('supabase error fetching repost sources:', error.message);
 100→        items.forEach(j => { j.repost_source = null; });
 101→        return journals;
 102→    }
 103→
 104→    const sourceMap = new Map(sources.map(s => [s.id, s]));
 105→    items.forEach(j => {
 106→        j.repost_source = j.repost_source_journal_id
 107→            ? (sourceMap.get(j.repost_source_journal_id) || null)
 108→            : null;
 109→    });
 110→
 111→    return journals;
 112→};
