 69→    }
 70→
 71→    if(validatedUsername){
 72→        data.username = validatedUsername;
 73→    }
 74→
 75→    const {data: uploadData, error:errorUploadData} = await supabase
 76→    .from('users')
 77→    .insert([data])
 78→
 79→    if(errorUploadData){
 80→        console.error('supabase error:', errorUploadData.message);
 81→        throw {status:500, error:'supabase error while uploading data'}
 82→    }
 83→
 84→    return true;
